514	              </Select>
515	            </div>
516	          )}
517	          <div>
518	            <Label className="text-xs text-muted-foreground">Message *</Label>
519	            <Textarea
520	              value={message}
521	              onChange={e => setMessage(e.target.value)}
522	              placeholder="Type your message here..."
523	              rows={5}
524	              className="mt-1 resize-none"
525	              data-testid="input-dm-message"
526	            />
527	            <p className="text-[10px] text-muted-foreground mt-1">{message.length} / 1000 characters</p>
528	          </div>
529	        </div>
530	        <DialogFooter>
531	          <Button variant="outline" onClick={onClose}>Cancel</Button>
532	          <Button
533	            onClick={() => sendMutation.mutate({ recipientId, message })}
534	            disabled={!recipientId.trim() || !message.trim() || sendMutation.isPending}
535	            className="gap-2"
536	            data-testid="button-send-dm"
537	          >
538	            <Send className="w-3.5 h-3.5" />
539	            {sendMutation.isPending ? "Sending..." : "Send DM"}
540	          </Button>
541	        </DialogFooter>
542	      </DialogContent>
543	    </Dialog>
544	  );
545	}
546	
547	export default function DMTracker({ useAdmin = false }: { useAdmin?: boolean }) {
548	  const { user } = useAuth();
549	  const { toast } = useToast();
550	  const Layout = useAdmin ? AdminLayout : ClientLayout;
551	  const isAdmin = useAdmin || user?.role === "admin";
552	
553	  const [view, setView] = useState<"pipeline" | "list">("pipeline");
554	  const [search, setSearch] = useState("");
555	  const [filterStatus, setFilterStatus] = useState("all");
556	  const [selectedClientId, setSelectedClientId] = useState<string>("all");
557	  const [addOpen, setAddOpen] = useState(false);
558	  const [editLead, setEditLead] = useState<any>(null);
559	  const [sendDMLead, setSendDMLead] = useState<any>(null);
560	
561	
562	  const { data: clients = [] } = useQuery<any[]>({
563	    queryKey: ["/api/clients"],
564	    enabled: isAdmin,
565	  });
566	
567	  const activeClientId = isAdmin ? (selectedClientId === "all" ? "" : selectedClientId) : (user?.id || "");
568	
569	  const { data: leads = [], isLoading } = useQuery<any[]>({
570	    queryKey: ["/api/dm/leads", activeClientId],
571	    queryFn: () => fetch(`/api/dm/leads${activeClientId ? `?clientId=${activeClientId}` : ""}`).then(r => r.json()),
572	  });
573	
574	  const deleteMutation = useMutation({
575	    mutationFn: (id: string) => apiRequest("DELETE", `/api/dm/leads/${id}`),
576	    onSuccess: () => {
577	      queryClient.invalidateQueries({ queryKey: ["/api/dm/leads"] });
578	      setEditLead(null);
579	      toast({ title: "Lead removed" });
580	    },
581	  });
582	
583	  const quickStatusMutation = useMutation({
584	    mutationFn: ({ id, status }: { id: string; status: string }) => apiRequest("PATCH", `/api/dm/leads/${id}`, { status }),
585	    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["/api/dm/leads"] }),
586	  });
587	
588	  const filtered = leads.filter(l => {
589	    const matchSearch = !search || l.name.toLowerCase().includes(search.toLowerCase()) || (l.instagramHandle || "").toLowerCase().includes(search.toLowerCase());
590	    const matchStatus = filterStatus === "all" || l.status === filterStatus;
591	    return matchSearch && matchStatus;
592	  });
593	
594	  const stats = {
595	    total: leads.length,
596	    hot: leads.filter(l => l.status === "hot").length,
597	    warm: leads.filter(l => l.status === "warm").length,
598	    cold: leads.filter(l => l.status === "cold").length,
599	    converted: leads.filter(l => l.status === "converted").length,
600	    new: leads.filter(l => l.status === "new").length,
601	  };
602	
603	  return (
604	    <Layout>
605	      <div className="p-6 space-y-6 max-w-7xl mx-auto">
606	        <div className="flex items-center justify-between gap-4 flex-wrap">
607	          <div className="flex items-center gap-3">
608	            <div className="w-10 h-10 bg-primary/10 rounded-xl flex items-center justify-center">
609	              <MessageCircle className="w-5 h-5 text-primary" />
610	            </div>
611	            <div>
612	              <h1 className="text-xl font-bold text-foreground">DM Tracker</h1>
613	              <p className="text-xs text-muted-foreground">Track and manage your Instagram leads</p>
614	            </div>
615	          </div>
616	          <div className="flex items-center gap-2">
617	            {isAdmin && clients.length > 0 && (
618	              <Select value={selectedClientId} onValueChange={setSelectedClientId}>
619	                <SelectTrigger className="w-44 h-9 text-xs" data-testid="select-filter-client">
620	                  <SelectValue placeholder="All clients" />
621	                </SelectTrigger>
622	                <SelectContent>
623	                  <SelectItem value="all">All clients</SelectItem>
624	                  {clients.map((c: any) => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}
625	                </SelectContent>
626	              </Select>
627	            )}
628	            <Button onClick={() => setAddOpen(true)} className="gap-2 h-9 text-sm" data-testid="button-add-lead">
629	              <Plus className="w-4 h-4" /> Add Lead
630	            </Button>
631	          </div>
632	        </div>
633	
634	        {/* Stats */}
635	        <div className="grid grid-cols-3 sm:grid-cols-6 gap-3">
636	          {[
637	            { label: "Total", val: stats.total, color: "text-foreground", bg: "bg-card border-card-border" },
638	            { label: "New", val: stats.new, color: "text-gray-400", bg: "bg-gray-500/10 border-gray-500/20" },
639	            { label: "Hot 🔥", val: stats.hot, color: "text-red-400", bg: "bg-red-500/10 border-red-500/20" },
640	            { label: "Warm", val: stats.warm, color: "text-amber-400", bg: "bg-amber-500/10 border-amber-500/20" },
641	            { label: "Cold", val: stats.cold, color: "text-blue-400", bg: "bg-blue-500/10 border-blue-500/20" },
642	            { label: "Converted ✅", val: stats.converted, color: "text-green-400", bg: "bg-green-500/10 border-green-500/20" },
643	          ].map(s => (
644	            <div key={s.label} className={`border rounded-xl p-3 text-center ${s.bg}`}>
645	              <p className={`text-xl font-bold ${s.color}`}>{s.val}</p>
646	              <p className="text-[10px] text-muted-foreground mt-0.5">{s.label}</p>
647	            </div>
648	          ))}
649	        </div>
650	
651	        <Tabs defaultValue="pipeline">
652	          <div className="flex items-center justify-between gap-3 flex-wrap">
653	            <TabsList>
654	              <TabsTrigger value="pipeline" className="gap-1.5 text-xs"><LayoutGrid className="w-3.5 h-3.5" />Pipeline</TabsTrigger>
655	              <TabsTrigger value="list" className="gap-1.5 text-xs"><List className="w-3.5 h-3.5" />List</TabsTrigger>
656	              <TabsTrigger value="quick-replies" className="gap-1.5 text-xs"><Zap className="w-3.5 h-3.5" />Quick Replies</TabsTrigger>
657	              <TabsTrigger value="instagram" className="gap-1.5 text-xs" data-testid="tab-instagram-connect"><Instagram className="w-3.5 h-3.5" />Instagram</TabsTrigger>
658	            </TabsList>
659	            <div className="flex items-center gap-2">
660	              <div className="relative">
661	                <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground" />
662	                <Input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search leads..." className="pl-8 h-8 text-xs w-44" data-testid="input-search-leads" />
663	              </div>
664	              <Select value={filterStatus} onValueChange={setFilterStatus}>
665	                <SelectTrigger className="h-8 text-xs w-32" data-testid="select-filter-status">
666	                  <SelectValue />
667	                </SelectTrigger>
668	                <SelectContent>
669	                  <SelectItem value="all">All Status</SelectItem>
670	                  {Object.entries(STATUS_CONFIG).map(([k, v]) => <SelectItem key={k} value={k}>{v.label}</SelectItem>)}
671	                </SelectContent>
672	              </Select>
673	            </div>
674	          </div>
675	
676	          {/* Pipeline View */}
677	          <TabsContent value="pipeline" className="mt-4">
678	            {isLoading ? (
679	              <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
680	                {PIPELINE_STATUSES.map(s => <Skeleton key={s} className="h-64 rounded-xl" />)}
681	              </div>
682	            ) : (
683	              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
684	                {PIPELINE_STATUSES.map(status => {
685	                  const cfg = STATUS_CONFIG[status];
686	                  const Icon = cfg.icon;
687	                  const col = filtered.filter(l => l.status === status);
688	                  return (
689	                    <div key={status} className={`rounded-xl border ${cfg.border} bg-card/30 p-3 space-y-2 min-h-[200px]`}>
690	                      <div className={`flex items-center justify-between mb-3`}>
691	                        <div className="flex items-center gap-2">
692	                          <div className={`w-6 h-6 rounded-lg flex items-center justify-center ${cfg.bg}`}>
693	                            <Icon className={`w-3.5 h-3.5 ${cfg.color}`} />
694	                          </div>
695	                          <span className={`text-xs font-semibold ${cfg.color}`}>{cfg.label}</span>
696	                        </div>
697	                        <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${cfg.bg} ${cfg.color}`}>{col.length}</span>
698	                      </div>
699	                      {col.length === 0 ? (
700	                        <div className="text-center py-8 opacity-40">
701	                          <Icon className={`w-6 h-6 ${cfg.color} mx-auto mb-1`} />
702	                          <p className="text-[10px] text-muted-foreground">No leads</p>
703	                        </div>
704	                      ) : (
705	                        col.map(lead => <LeadCard key={lead.id} lead={lead} onClick={() => setEditLead(lead)} onSendDM={setSendDMLead} />)
706	                      )}
707	                    </div>
708	                  );
709	                })}
710	              </div>
711	            )}
712	          </TabsContent>
713	
714	          {/* List View */}
715	          <TabsContent value="list" className="mt-4">
716	            {isLoading ? (
717	              <div className="space-y-2">{[1,2,3,4,5].map(i => <Skeleton key={i} className="h-14 rounded-xl" />)}</div>
718	            ) : filtered.length === 0 ? (
719	              <div className="text-center py-16 border border-dashed border-border rounded-2xl">
720	                <MessageCircle className="w-10 h-10 text-muted-foreground mx-auto mb-3 opacity-30" />
721	                <p className="text-sm text-muted-foreground">No leads found</p>
722	              </div>
723	            ) : (
724	              <div className="border border-card-border rounded-xl overflow-hidden">
725	                <table className="w-full text-sm">
726	                  <thead>
727	                    <tr className="border-b border-card-border bg-card/60">
728	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground">Name</th>
729	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground hidden sm:table-cell">Handle</th>
730	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground">Status</th>
731	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground hidden md:table-cell">Source</th>
732	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground hidden lg:table-cell">Follow-Up</th>
733	                      <th className="text-left px-4 py-3 text-xs font-semibold text-muted-foreground hidden lg:table-cell">Notes</th>
734	                      <th className="px-4 py-3"></th>
735	                    </tr>
736	                  </thead>
737	                  <tbody>
738	                    {filtered.map((lead, i) => {
739	                      const overdue = lead.followUpDate && isPast(new Date(lead.followUpDate)) && !isToday(new Date(lead.followUpDate));
740	                      return (
741	                        <tr key={lead.id} className={`border-b border-card-border/50 hover:bg-card/60 transition-colors ${i % 2 === 0 ? "" : "bg-card/20"}`} data-testid={`lead-row-${lead.id}`}>
742	                          <td className="px-4 py-3 font-medium text-foreground text-sm">{lead.name}</td>
743	                          <td className="px-4 py-3 text-muted-foreground text-xs hidden sm:table-cell">
744	                            {lead.instagramHandle ? <span className="flex items-center gap-1"><Instagram className="w-3 h-3 text-pink-400" />@{lead.instagramHandle}</span> : "—"}
745	                          </td>
746	                          <td className="px-4 py-3"><StatusBadge status={lead.status} /></td>
747	                          <td className="px-4 py-3 text-xs text-muted-foreground hidden md:table-cell">{lead.source || "—"}</td>
748	                          <td className={`px-4 py-3 text-xs hidden lg:table-cell ${overdue ? "text-red-400 font-medium" : "text-muted-foreground"}`}>
749	                            {lead.followUpDate ? format(new Date(lead.followUpDate), "MMM d, yyyy") : "—"}
750	                          </td>
751	                          <td className="px-4 py-3 text-xs text-muted-foreground hidden lg:table-cell max-w-[180px] truncate">{lead.notes || "—"}</td>
752	                          <td className="px-4 py-3">
753	                            <button onClick={() => setEditLead(lead)} className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors">
754	                              <Edit2 className="w-3.5 h-3.5" />
755	                            </button>
756	                          </td>
757	                        </tr>
758	                      );
759	                    })}
760	                  </tbody>
761	                </table>
762	              </div>
763	            )}
764	          </TabsContent>
765	
766	          {/* Quick Replies */}
767	          <TabsContent value="quick-replies" className="mt-4 max-w-2xl">
768	            <QuickRepliesPanel clientId={activeClientId} isAdmin={isAdmin} />
769	          </TabsContent>
770	
771	          {/* Instagram Connection */}
772	          <TabsContent value="instagram" className="mt-4">
773	            <InstagramConnectPanel clientId={activeClientId} />
774	          </TabsContent>
775	        </Tabs>
776	
777	        {/* Add Lead Dialog */}
778	        <AddEditLeadDialog
779	          open={addOpen}
780	          onClose={() => setAddOpen(false)}
781	          clientId={activeClientId}
782	          clients={isAdmin ? clients : undefined}
783	          isAdmin={isAdmin}
784	        />
785	
786	        {/* Send DM Dialog */}
787	        {sendDMLead && (
788	          <SendDMDialog
789	            open={!!sendDMLead}
790	            onClose={() => setSendDMLead(null)}
791	            lead={sendDMLead}
792	            clientId={activeClientId}
793	          />
794	        )}
795	
796	        {/* Edit Lead Dialog */}
797	        {editLead && (
798	          <Dialog open={!!editLead} onOpenChange={v => !v && setEditLead(null)}>
799	            <DialogContent className="max-w-md">
800	              <DialogHeader>
801	                <DialogTitle className="flex items-center justify-between">
802	                  <span>{editLead.name}</span>
803	                  <button onClick={() => { if (confirm("Delete this lead?")) deleteMutation.mutate(editLead.id); }} className="text-muted-foreground hover:text-destructive transition-colors p-1 rounded-lg hover:bg-accent">
804	                    <Trash2 className="w-4 h-4" />
805	                  </button>
806	                </DialogTitle>
807	              </DialogHeader>
808	              <div className="py-2">
809	                <p className="text-xs text-muted-foreground mb-4">Quick status change:</p>
810	                <div className="flex flex-wrap gap-2 mb-4">
811	                  {Object.entries(STATUS_CONFIG).map(([k, v]) => {
812	                    const Icon = v.icon;
813	                    return (
814	                      <button
815	                        key={k}
816	                        onClick={() => { quickStatusMutation.mutate({ id: editLead.id, status: k }); setEditLead({ ...editLead, status: k }); }}
817	                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${editLead.status === k ? `${v.bg} ${v.border} ${v.color}` : "border-border text-muted-foreground hover:border-primary/30"}`}
818	                      >
819	                        <Icon className="w-3 h-3" />{v.label}
820	                      </button>
821	                    );
822	                  })}
823	                </div>
824	                <p className="text-xs text-muted-foreground">Or click Edit to update all details:</p>
825	              </div>
826	              <DialogFooter>
827	                <Button variant="outline" onClick={() => setEditLead(null)}>Close</Button>
828	                <Button onClick={() => { setSendDMLead(editLead); setEditLead(null); }} variant="secondary" className="gap-2" data-testid="button-send-dm-from-detail">
829	                  <Send className="w-3.5 h-3.5" /> Send DM
830	                </Button>
831	                <Button onClick={() => { const l = editLead; setEditLead(null); setTimeout(() => setEditLead(l), 10); }} className="gap-2">
832	                  <Edit2 className="w-3.5 h-3.5" /> Edit Details
833	                </Button>
834	              </DialogFooter>
835	            </DialogContent>
836	          </Dialog>
837	        )}
838	      </div>
839	    </Layout>
840	  );
841	}
