                <ShieldCheck className="w-4 h-4" /> Connected
              </p>
              <p className="text-xs text-muted-foreground mt-0.5">
                @{account.igUsername} · {account.pageName}
                {account.followersCount != null && ` · ${account.followersCount.toLocaleString()} followers`}
