app.get("/api/dm/comment-replies", requireAuth, async (req: Request, res: Response) => {
  try {
    const userId = (req.user as any).id;
    const qUserId = req.query.userId as string;
    const targetId = (req.user as any).role === "admin" && qUserId ? qUserId : userId;
    const rows = await db.select().from(commentAutoReplies).where(eq(commentAutoReplies.userId, targetId)).orderBy(desc(commentAutoReplies.createdAt));
    res.json(rows);
  } catch (err: any) { res.status(500).json({ message: err.message }); }
});

app.post("/api/dm/comment-replies", requireAuth, async (req: Request, res: Response) => {
  try {
    const userId = req.body.userId || (req.user as any).id;
    const [row] = await db.insert(commentAutoReplies).values({ ...req.body, userId }).returning();
    res.json(row);
  } catch (err: any) { res.status(500).json({ message: err.message }); }
});

