app.post("/api/dm/ai-bot/test", requireAuth, async (req: Request, res: Response) => {
  try {
    const userId = (req.user as any).id;
    const { message } = req.body;
    const [config] = await db.select().from(aiBotConfigs).where(eq(aiBotConfigs.userId, userId));
    const apiKey = process.env.ANTHROPIC2_API_KEY || process.env.ANTHROPIC_API_KEY;
    if (!apiKey) return res.status(400).json({ message: "AI not configured" });
    const client = new Anthropic({ apiKey });
    const personality = config?.personality || "friendly";
    const instructions = config?.instructions || "";
    const systemPrompt = `You are an Instagram DM assistant. Be ${personality} and concise (max 3 sentences). ${instructions} Never reveal you are AI unless directly asked.`;
    const response = await client.messages.create({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 200,
      system: systemPrompt,
      messages: [{ role: "user", content: message }],
    });
    const reply = (response.content[0] as any).text;
    res.json({ reply });
  } catch (err: any) { res.status(500).json({ message: err.message }); }
});

