// ── DM Conversations (Live Chat via Meta API) ──────────────────────────────
app.get("/api/dm/conversations", requireAuth, async (req: Request, res: Response) => {
  try {
    const userId = (req.user as any).id;
    const token = await db.select().from(metaTokens).where(eq(metaTokens.userId, userId));
    if (!token[0]?.accessToken) return res.json({ conversations: [], connected: false });
    const igId = token[0].igAccountId;
    if (!igId) return res.json({ conversations: [], connected: false });
    const url = `https://graph.facebook.com/v18.0/${igId}/conversations?platform=instagram&fields=participants,messages{message,from,created_time}&access_token=${token[0].accessToken}&limit=20`;
    const response = await fetch(url);
    const data = await response.json() as any;
    if (data.error) return res.json({ conversations: [], error: data.error.message, connected: true });
    res.json({ conversations: data.data || [], connected: true });
  } catch (err: any) { res.status(500).json({ message: err.message }); }
});

app.get("/api/dm/conversations/:igUserId/messages", requireAuth, async (req: Request, res: Response) => {
  try {
    const userId = (req.user as any).id;
    const token = await db.select().from(metaTokens).where(eq(metaTokens.userId, userId));
    if (!token[0]?.accessToken) return res.status(400).json({ message: "Instagram not connected" });
    const igId = token[0].igAccountId;
    const url = `https://graph.facebook.com/v18.0/${igId}/conversations?platform=instagram&user_id=${req.params.igUserId}&fields=messages{message,from,created_time,attachments}&access_token=${token[0].accessToken}`;
    const response = await fetch(url);
    const data = await response.json() as any;
    const messages = data.data?.[0]?.messages?.data || [];
    res.json({ messages: messages.reverse() });
  } catch (err: any) { res.status(500).json({ message: err.message }); }
});

