export async function sendInstagramDM(recipientId: string, messageText: string): Promise<{ messageId: string }> {
  const token = await getActiveToken();
  if (!token) throw new Error("META_ACCESS_TOKEN not configured");
  const url = `https://graph.instagram.com/v25.0/me/messages`;
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
    body: JSON.stringify({
      recipient: { id: recipientId },
      message: { text: messageText },
    }),
  });
  const data = await res.json() as any;
  if (data?.error) throw new Error(`Instagram DM: ${data.error.message} (code ${data.error.code})`);
  return { messageId: data.message_id || data.id || "sent" };
}

