// ── Section: Welcome DM ───────────────────────────────────────────────────
function WelcomeDMSection({ userId }: { userId: string }) {
  const { toast } = useToast();
  const [cfg, setCfg] = useState({ isActive: false, message: "", delayMinutes: 0 });
